// marshalEnvelope produces a deterministic byte ordering that mirrors
// the natural JSON-RPC field order: jsonrpc, id, method, params, result,
// error, _meta. Tests rely on byte-stable output for golden comparison.
func marshalEnvelope(f envelopeFields) ([]byte, error) {
	var buf bytes.Buffer
	buf.WriteByte('{')
	first := true

	writeKey := func(key string) {
		if !first {
			buf.WriteByte(',')
		}
		first = false
		buf.WriteByte('"')
		buf.WriteString(key)
		buf.WriteString(`":`)
	}

	if f.jsonrpc {
		writeKey("jsonrpc")
		buf.WriteString(`"` + JSONRPCVersion + `"`)
	}
	if f.hasID {
		writeKey("id")
		idBytes, err := f.id.MarshalJSON()
		if err != nil {
			return nil, err
		}
		buf.Write(idBytes)
	}
	if f.method != "" {
		writeKey("method")
		mb, err := json.Marshal(f.method)
		if err != nil {
			return nil, err
		}
		buf.Write(mb)
	}
	if f.params != nil {
		writeKey("params")
		buf.Write(f.params)
	}
	if f.result != nil {
		writeKey("result")
		buf.Write(f.result)
	}
	if f.errorObj != nil {
		writeKey("error")
		eb, err := json.Marshal(f.errorObj)
		if err != nil {
			return nil, err
		}
		buf.Write(eb)
	}
	if len(f.meta) != 0 {
		writeKey("_meta")
		buf.Write(f.meta)
	}
	buf.WriteByte('}')
	return buf.Bytes(), nil
}

